  1→using System;
  2→using System.Collections.Generic;
  3→using System.IO;
  4→using System.Linq;
  5→
  6→public class IniFile
  7→{
  8→    private readonly string _filePath;
  9→    // 생성자
 10→    public IniFile(string filePath)
 11→    {
 12→        _filePath = filePath;
 13→    }
 14→    // 설정값 읽기
 15→    public string ReadValue(string section, string key)
 16→    {
 17→        string value = "";
 18→        try
 19→        {
 20→            if (!File.Exists(_filePath))
 21→            {
 22→                Console.WriteLine("INI 파일이 존재하지 않습니다.");
 23→                return value;
 24→            }
 25→
 26→            string[] lines = File.ReadAllLines(_filePath);
 27→            bool inSection = false;
 28→
 29→            foreach (string line in lines)
 30→            {
 31→                string trimmedLine = line.Trim();
 32→
 33→                // 섹션 찾기
 34→                if (trimmedLine.StartsWith("[") && trimmedLine.EndsWith("]"))
 35→                {
 36→                    inSection = trimmedLine.Trim('[', ']') == section;
 37→                }
 38→                else if (inSection && trimmedLine.Contains("="))
 39→                {
 40→                    string[] parts = trimmedLine.Split(new[] { '=' }, 2);
 41→                    if (parts[0].Trim() == key)
 42→                    {
 43→                        value = parts[1].Trim();
 44→                        break;
 45→                    }
 46→                }
 47→            }
 48→        }
 49→        catch (Exception ex)
 50→        {
 51→            Console.WriteLine("INI 읽기 오류: " + ex.Message);
 52→        }
 53→
 54→        return value;
 55→    }
 56→    // 설정값 저장
 57→    public void WriteValue(string section, string key, string value)
 58→    {
 59→        try
 60→        {
 61→            List<string> lines = File.Exists(_filePath)
 62→                ? File.ReadAllLines(_filePath).ToList()
 63→                : new List<string>();
 64→
 65→            List<string> newLines = new List<string>();
 66→            bool inSection = false;
 67→            bool sectionExists = false;
 68→            bool keyWritten = false;
 69→
 70→            for (int i = 0; i < lines.Count; i++)
 71→            {
 72→                string line = lines[i].Trim();
 73→
 74→                if (line.StartsWith("[") && line.EndsWith("]"))
 75→                {
 76→                    if (inSection && !keyWritten)
 77→                    {
 78→                        newLines.Add($"{key}={value}");
 79→                        keyWritten = true;
 80→                    }
 81→
 82→                    string currentSection = line.Trim('[', ']');
 83→                    inSection = currentSection.Equals(section, StringComparison.OrdinalIgnoreCase);
 84→                    sectionExists |= inSection;
 85→
 86→                    newLines.Add(lines[i]);
 87→                    continue;
 88→                }
 89→
 90→                if (inSection && line.Contains("="))
 91→                {
 92→                    string[] parts = line.Split(new[] { '=' }, 2);
 93→                    if (parts[0].Trim() == key)
 94→                    {
 95→                        newLines.Add($"{key}={value}");
 96→                        keyWritten = true;
 97→                        continue;
 98→                    }
 99→                }
100→
101→                newLines.Add(lines[i]);
102→            }
103→
104→            if (!sectionExists)
105→            {
106→                newLines.Add($"[{section}]");
107→            }
108→
109→            if (!keyWritten)
110→            {
111→                newLines.Add($"{key}={value}");
112→            }
113→
114→            File.WriteAllLines(_filePath, newLines);
115→        }
116→        catch (Exception ex)
117→        {
118→            Console.WriteLine("INI 쓰기 오류: " + ex.Message);
119→        }
120→    }
121→}
