 10→        public static void InitGraph(
 11→    ZedGraphControl zg,
 12→    string title,
 13→    string yTitle,
 14→    double yMin,
 15→    double yMax,
 16→    double rollingWindowSec = 60,
 17→    int pointsCapacity = 3000,
 18→    bool clearAll = true,
 19→    Color? curveColor = null,
 20→    float lineWidth = 3.0f,
 21→    string xTitle = "Distance (mm)"  // X축 제목 (기본값: 거리)
 22→)
 23→        {
 24→            // ── 라이트 테마 색상
 25→            Color bgOuter = Color.White;
 26→            Color bgChart = Color.FromArgb(250, 250, 250);
 27→            Color fg = Color.FromArgb(33, 33, 33);
 28→            Color gridColor = Color.FromArgb(210, 210, 210);
 29→            Color lineColor = curveColor ?? Color.FromArgb(25, 118, 210);
 30→            Color peakColor = Color.FromArgb(255, 160, 0);
 31→
 32→            GraphPane pane = zg.GraphPane;
 33→            zg.IsAntiAlias = true;
 34→
 35→            if (clearAll)
 36→            {
 37→                pane.CurveList.Clear();
 38→                pane.GraphObjList.Clear();
 39→                zg.ZoomOutAll(pane);
 40→            }
 41→
 42→            pane.Title.Text = title;
 43→            pane.Title.IsVisible = !string.IsNullOrEmpty(title);
 44→            pane.Title.FontSpec.Size = 36;
 45→            pane.Title.FontSpec.FontColor = fg;
 46→
 47→            pane.XAxis.Title.Text = xTitle;
 48→            pane.YAxis.Title.Text = yTitle;
 49→
 50→            pane.XAxis.Type = AxisType.Linear;
 51→            pane.XAxis.Scale.Min = 0;
 52→            pane.XAxis.Scale.Max = rollingWindowSec;
 53→            pane.XAxis.Scale.MajorStep = 1;  // X축 1mm 단위
 54→            pane.XAxis.Scale.MinorStep = 0.5;
 55→
 56→            pane.YAxis.Scale.Min = yMin;
 57→            pane.YAxis.Scale.Max = yMax;
 58→            pane.YAxis.Scale.MajorStep = 5;  // Y축 5 단위
 59→            pane.YAxis.Scale.MinorStep = 1;
 60→
 61→            // 그리드 설정 (얇은 회색 선)
 62→            Color lightGridColor = Color.FromArgb(200, 200, 200);  // 얅은 회색
 63→            pane.XAxis.MajorGrid.IsVisible = true;
 64→            pane.XAxis.MajorGrid.Color = lightGridColor;
 65→            pane.XAxis.MajorGrid.DashOff = 0;
 66→            pane.XAxis.MajorGrid.PenWidth = 0.5f;  // 얇은 선
 67→
 68→            pane.YAxis.MajorGrid.IsVisible = true;
 69→            pane.YAxis.MajorGrid.Color = lightGridColor;
 70→            pane.YAxis.MajorGrid.DashOff = 0;
 71→            pane.YAxis.MajorGrid.PenWidth = 0.5f;  // 얇은 선
 72→
 73→            pane.Fill = new Fill(bgOuter);
 74→            pane.Chart.Fill = new Fill(bgChart);
 75→
 76→            pane.XAxis.Scale.FontSpec.Size = 22f;
 77→            pane.YAxis.Scale.FontSpec.Size = 22f;
 78→            pane.XAxis.Title.FontSpec.Size = 24f;
 79→            pane.YAxis.Title.FontSpec.Size = 24f;
 80→
 81→            pane.XAxis.Scale.FontSpec.FontColor = fg;
 82→            pane.YAxis.Scale.FontSpec.FontColor = fg;
 83→            pane.XAxis.Title.FontSpec.FontColor = fg;
 84→            pane.YAxis.Title.FontSpec.FontColor = fg;
 85→
 86→            pane.XAxis.Color = fg;
 87→            pane.YAxis.Color = fg;
 88→            pane.Border.IsVisible = true;
 89→            pane.Border.Color = Color.FromArgb(189, 189, 189);
 90→
 91→            pane.Legend.IsVisible = false;
 92→
 93→            var rolling = new RollingPointPairList(pointsCapacity);
 94→            var curve = pane.AddCurve(
 95→                string.IsNullOrEmpty(title) ? "Series" : title,
 96→                rolling,
 97→                lineColor,
 98→                SymbolType.None
 99→            );
100→
101→            curve.Line.Width = lineWidth; // ← 사용자 지정 굵기 적용
102→            curve.Line.IsSmooth = true;
103→            curve.Line.SmoothTension = 0.1f;
104→
105→            var peakLine = new LineObj(peakColor, 0, 0, 0, 0)
106→            {
107→                IsVisible = false,
108→                Tag = "PEAK_LINE"
109→            };
110→            pane.GraphObjList.Add(peakLine);
111→
112→            var peakText = new TextObj("", 0, 0, CoordType.AxisXYScale, AlignH.Center, AlignV.Top)
113→            {
114→                IsVisible = false,
115→                Tag = "PEAK_TEXT",
116→                FontSpec = new FontSpec("Arial Narrow", 18f, peakColor, false, false, false)
117→                {
118→                    Border = { IsVisible = false },
119→                    Fill = new Fill(Color.Transparent)
120→                }
121→            };
122→            pane.GraphObjList.Add(peakText);
123→
124→            zg.AxisChange();
125→            zg.Invalidate();
126→        }
