128→        public static void DrawGraph(ZedGraphControl zg, double yValue, double xValue)
129→        {
130→            System.Diagnostics.Debug.WriteLine($"[DrawGraph] 호출됨 - xValue={xValue:F3}, yValue={yValue:F3}");
131→
132→            if (zg == null)
133→            {
134→                System.Diagnostics.Debug.WriteLine("[DrawGraph] zg가 null - 종료");
135→                return;
136→            }
137→
138→            var pane = zg.GraphPane;
139→            if (pane.CurveList.Count == 0)
140→            {
141→                System.Diagnostics.Debug.WriteLine("[DrawGraph] CurveList가 비어있음 - InitGraph가 호출되지 않음!");
142→                return;
143→            }
144→
145→            var curve = pane.CurveList[0];
146→            var pts = curve.Points as IPointListEdit;
147→            if (pts == null)
148→            {
149→                System.Diagnostics.Debug.WriteLine("[DrawGraph] pts가 null - 종료");
150→                return;
151→            }
152→
153→            // 데이터 추가
154→            pts.Add(xValue, yValue);
155→            System.Diagnostics.Debug.WriteLine($"[DrawGraph] 데이터 추가됨 - 총 포인트 수: {pts.Count}");
156→
157→            // X축 롤링 (최근 범위 표시)
158→            pane.XAxis.Scale.Min = 0;
159→            pane.XAxis.Scale.Max = xValue > 1 ? xValue : 1;  // 최소 1 이상으로 설정
160→
161→            zg.AxisChange();
162→            zg.Invalidate();
163→        }
