  7→public class ClassSerialGather : IDisposable
  8→{
  9→    private SerialPort _serialPort;
 10→    private Thread _readThread;
 11→    private Timer _pollTimer;
 12→    private bool _isRunning;
 13→    private StringBuilder _recvBuffer;
 14→    private readonly object _lockObject = new object();
 15→    
 16→    //50 52 45 53 53 55 52 45 3F 0D 0A
 17→    // Send 프로토콜: 50 52 45 53 53 55 52 45 3F 0D 0A = "PRESSURE?\r\n"
 18→    private readonly byte[] _sendProtocol = { 0x50, 0x52, 0x45, 0x53, 0x53, 0x55, 0x52, 0x45, 0x3F, 0x0D, 0x0A };
 19→    
 20→    // Recv 종료 시퀀스: 0D 0A = "\r\n"
 21→    private readonly byte[] _recvEndSequence = { 0x0D, 0x0A };
 22→    
 23→    private int _pollingInterval = 200; // ms
 24→    
 25→    // 로그 출력 플래그
 26→    public bool EnableLog { get; set; } = false;
 27→    
 28→    // 사용/미사용 플래그
 29→    public bool Enabled { get; set; } = false;
 30→    
 31→    // 수신 데이터 프로퍼티
 32→    public string ReceivedData { get; private set; } = string.Empty;
 33→    
 34→    // 연결 상태
 35→    public bool IsOpen => _serialPort != null && _serialPort.IsOpen;
 36→    
 37→    // 데이터 수신 이벤트
 38→    public event Action<string> DataReceived;
 39→    
 40→    public ClassSerialGather(string portName, int baudRate = 9600, int pollingInterval = 200)
 41→    {
 42→        _serialPort = new SerialPort(portName, baudRate, Parity.None, 8, StopBits.One)
 43→        {
 44→            ReadTimeout = 1000,
 45→            WriteTimeout = 1000
 46→        };
 47→        
 48→        _recvBuffer = new StringBuilder();
 49→        _pollingInterval = pollingInterval;
 50→    }
 51→    
 52→    public bool Open()
 53→    {
 54→        // 미사용 모드면 실제로 열지 않고 성공 반환
 55→        if (!Enabled)
 56→        {
 57→            Log($"Serial 포트 미사용 모드: {_serialPort.PortName}");
 58→            return true;
 59→        }
 60→        
 61→        try
 62→        {
 63→            if (_serialPort.IsOpen)
 64→                return true;
 65→            
 66→            _serialPort.Open();
 67→            
 68→            if (_serialPort.IsOpen)
 69→            {
 70→                _isRunning = true;
 71→                
 72→                // 읽기 스레드 시작
 73→                _readThread = new Thread(ReadThreadTask)
 74→                {
 75→                    IsBackground = true
 76→                };
 77→                _readThread.Start();
 78→                
 79→                // 폴링 타이머 시작
 80→                _pollTimer = new Timer(PollTimerCallback, null, 0, _pollingInterval);
 81→                
 82→                Log($"Serial 포트 열림: {_serialPort.PortName}, BaudRate: {_serialPort.BaudRate}, Polling: {_pollingInterval}ms");
 83→                return true;
 84→            }
 85→        }
 86→        catch (Exception ex)
 87→        {
 88→            Log($"Serial 포트 열기 실패: {ex.Message}");
 89→        }
 90→        return false;
 91→    }
 92→    
 93→    public void Close()
 94→    {
 95→        _isRunning = false;
 96→        
 97→        // 타이머 정지
 98→        if (_pollTimer != null)
 99→        {
100→            _pollTimer.Dispose();
101→            _pollTimer = null;
102→        }
103→        
104→        // 읽기 스레드 종료
105→        if (_readThread != null && _readThread.IsAlive)
106→        {
107→            _readThread.Join(1000);
108→        }
109→        
110→        // 시리얼 포트 닫기
111→        if (_serialPort != null && _serialPort.IsOpen)
112→        {
113→            _serialPort.Close();
114→            Log("Serial 포트 닫힘");
115→        }
116→    }
117→    
118→    private void PollTimerCallback(object state)
119→    {
120→        if (!Enabled || !_isRunning || _serialPort == null || !_serialPort.IsOpen)
121→            return;
122→        
123→        try
124→        {
125→            _serialPort.Write(_sendProtocol, 0, _sendProtocol.Length);
126→            Log($"Send: {BitConverter.ToString(_sendProtocol)}");
127→        }
128→        catch (Exception ex)
129→        {
130→            Log($"Send 오류: {ex.Message}");
131→        }
132→    }
133→    
134→    private void ReadThreadTask()
135→    {
136→        byte[] buffer = new byte[1024];
137→        
138→        while (Enabled && _isRunning && _serialPort != null && _serialPort.IsOpen)
139→        {
140→            try
141→            {
142→                if (_serialPort.BytesToRead > 0)
143→                {
144→                    int bytesRead = _serialPort.Read(buffer, 0, Math.Min(buffer.Length, _serialPort.BytesToRead));
145→                    
146→                    if (bytesRead > 0)
147→                    {
148→                        lock (_lockObject)
149→                        {
150→                            // 수신 데이터를 버퍼에 추가
151→                            for (int i = 0; i < bytesRead; i++)
152→                            {
153→                                _recvBuffer.Append((char)buffer[i]);
154→                            }
155→                            
156→                            // 종료 시퀀스(0D 0A) 확인
157→                            string data = _recvBuffer.ToString();
158→                            int endIndex = FindEndSequence(data);
159→                            
160→                            if (endIndex >= 0)
161→                            {
162→                                // 종료 시퀀스까지의 데이터 추출
163→                                string received = data.Substring(0, endIndex);
164→                                
165→                                // 쉼표(2C)로 구분해서 앞부분만 추출
166→                                string[] parts = received.Split(',');
167→                                string pressureValue = parts.Length > 0 ? parts[0].Trim() : received;
168→                                
169→                                ReceivedData = pressureValue;
170→                                
171→                                // 이벤트 발생 (앞부분만 전달)
172→                                DataReceived?.Invoke(pressureValue);
173→                                
174→                                Log($"Recv: {received} → 파싱: {pressureValue}");
175→                                
176→                                // 버퍼 정리 (종료 시퀀스 이후 데이터는 다음 패킷으로)
177→                                if (endIndex + 2 < data.Length)
178→                                {
179→                                    _recvBuffer.Clear();
180→                                    _recvBuffer.Append(data.Substring(endIndex + 2));
181→                                }
182→                                else
183→                                {
184→                                    _recvBuffer.Clear();
185→                                }
186→                            }
187→                        }
188→                    }
189→                }
190→            }
191→            catch (TimeoutException)
192→            {
193→                // 타임아웃은 정상 동작
194→            }
195→            catch (Exception ex)
196→            {
197→                Log($"Serial 읽기 오류: {ex.Message}");
198→            }
199→            
200→            Thread.Sleep(10);
201→        }
202→    }
203→    
204→    private int FindEndSequence(string data)
205→    {
206→        // 종료 시퀀스 0D 0A (\r\n) 찾기
207→        for (int i = 0; i < data.Length - 1; i++)
208→        {
209→            if (data[i] == '\r' && data[i + 1] == '\n')
210→            {
211→                return i;
212→            }
213→        }
214→        return -1;
215→    }
216→    
217→    private void Log(string message)
218→    {
219→        if (EnableLog)
220→        {
221→            Logger.Log($"[SerialGather] {message}");
222→        }
223→    }
224→    
225→    public void Dispose()
226→    {
227→        Close();
228→        
229→        if (_serialPort != null)
230→        {
231→            _serialPort.Dispose();
232→            _serialPort = null;
233→        }
234→    }
235→}
