  7→/// <summary>
  8→/// 3D CSV 전용 파서 (StreamReader 방식)
  9→/// CSV 포맷: 첫 행 = Y값 헤더, 이후 행 = X값 + Z값
 10→/// 메타데이터: #TYPE,3D / #TITLE,... (선택)
 11→/// </summary>
 12→public static class CsvParser
 13→{
 14→    public static (CsvData3D? data, string? error) Parse(string filePath)
 15→    {
 16→        try
 17→        {
 18→            if (!File.Exists(filePath))
 19→                return (null, $"파일을 찾을 수 없습니다: {filePath}");
 20→
 21→            var title = "";
 22→            var dataLines = new List<string>();
 23→
 24→            // StreamReader로 순차 읽기 (대용량 CSV 메모리 최적화)
 25→            using (var reader = new StreamReader(filePath))
 26→            {
 27→                string? line;
 28→                while ((line = reader.ReadLine()) != null)
 29→                {
 30→                    if (string.IsNullOrWhiteSpace(line))
 31→                        continue;
 32→
 33→                    // 메타데이터 처리
 34→                    if (line.StartsWith('#'))
 35→                    {
 36→                        var parts = line.Split(',', 2);
 37→                        if (parts.Length == 2 && parts[0].Equals("#TITLE", StringComparison.OrdinalIgnoreCase))
 38→                            title = parts[1].Trim();
 39→                        continue;
 40→                    }
 41→
 42→                    dataLines.Add(line);
 43→                }
 44→            }
 45→
 46→            if (dataLines.Count < 2)
 47→                return (null, "데이터가 부족합니다 (최소 2행 필요)");
 48→
 49→            // 첫 행 = Y값 헤더
 50→            var headerParts = dataLines[0].Split(',');
 51→            int colCount = headerParts.Length - 1; // 첫 번째 셀 제외
 52→            if (colCount < 1)
 53→                return (null, "Y값 헤더가 없습니다");
 54→
 55→            var yValues = new double[colCount];
 56→            for (int c = 0; c < colCount; c++)
 57→            {
 58→                if (!double.TryParse(headerParts[c + 1].Trim(), NumberStyles.Float,
 59→                    CultureInfo.InvariantCulture, out yValues[c]))
 60→                    yValues[c] = c; // 파싱 실패 시 인덱스 사용
 61→            }
 62→
 63→            // 데이터 행 파싱
 64→            int rowCount = dataLines.Count - 1;
 65→            var xValues = new double[rowCount];
 66→            var zValues = new double[rowCount, colCount];
 67→
 68→            for (int r = 0; r < rowCount; r++)
 69→            {
 70→                var parts = dataLines[r + 1].Split(',');
 71→
 72→                // X값
 73→                if (parts.Length > 0 && double.TryParse(parts[0].Trim(), NumberStyles.Float,
 74→                    CultureInfo.InvariantCulture, out double x))
 75→                    xValues[r] = x;
 76→                else
 77→                    xValues[r] = r;
 78→
 79→                // Z값
 80→                for (int c = 0; c < colCount; c++)
 81→                {
 82→                    int idx = c + 1;
 83→                    if (idx < parts.Length)
 84→                    {
 85→                        var cell = parts[idx].Trim();
 86→                        if (string.IsNullOrEmpty(cell))
 87→                            zValues[r, c] = double.NaN;
 88→                        else if (!double.TryParse(cell, NumberStyles.Float,
 89→                            CultureInfo.InvariantCulture, out zValues[r, c]))
 90→                            zValues[r, c] = double.NaN;
 91→                    }
 92→                    else
 93→                    {
 94→                        zValues[r, c] = double.NaN;
 95→                    }
 96→                }
 97→            }
 98→
 99→            var data = new CsvData3D
100→            {
101→                Title = title,
102→                FilePath = filePath,
103→                XValues = xValues,
104→                YValues = yValues,
105→                ZValues = zValues
106→            };
107→
108→            return (data, null);
109→        }
110→        catch (Exception ex)
111→        {
112→            return (null, $"CSV 파싱 오류: {ex.Message}");
113→        }
114→    }
115→}
