private System.Windows.Forms.Timer tmrIO;

// 초기화
tmrIO = new System.Windows.Forms.Timer();
tmrIO.Interval = 50;  // 20Hz
tmrIO.Tick += (s, e) => TimerTick();
tmrIO.Start();

private void TimerTick() {
  try {
    // 상태머신
    switch (_state) {
      case 0:  // 읽기 1
        // PLC 읽기
        _state = 1;
        break;
      case 1:  // 읽기 2
        // PLC 읽기
        _state = 2;
        break;
      case 2:  // 쓰기 1
        // PLC 쓰기
        _state = 3;
        break;
      // ... 더 많은 상태들
    }
  }
  catch (Exception ex) {
    Logger.Log($"[TimerTick] {ex.Message}");
  }
}
